+    if input.len() < 2 {
+        return None;
+    }
+    let bytes = input.as_bytes();
+    let first = bytes[0];
+    let last = bytes[bytes.len() - 1];
+    if (first == b'\'' && last == b'\'') || (first == b'"' && last == b'"') {
+        let inner = &input[1..input.len() - 1];
+        if inner.contains('\n') || inner.contains('\r') {
+            return None;
+        }
+        return Some(inner.to_string());
+    }
+    None
